function fmt(n) { try { return n.toLocaleString(); } catch (e) { return "" + n; } }

// deferred in-file navigation stub (mirrors the app-frame external glyph; no real cross-file link)
function navStub(target) {
  return function (e) { if (e) e.stopPropagation(); void target; /* NOTE(nav): → wireframes/mobile/<target> (deferred) */ };
}
// transparent, hit-testable click target appended on top of card content
function clickRect(g, x, y, w, h, onClick) {
  var r = rect(x, y, w, h, 4, "#ffffff"); r.setAttribute("opacity", "0"); r.style.cursor = "pointer";
  r.addEventListener("click", onClick); g.appendChild(r);
}
// author verification tag: 0 None (no tag) · 1 Identity · 2 Residency · 3 Official (MLA / gov)
function tierLabel(t) { return ["", "Identity", "Residency", "Official"][t] || ""; }
function hasReactions(p) { return p.type === "statement" || p.type === "result"; }
var FEED_TYPE_NAME = { statement: "Statements", petition: "Petitions", poll: "Polls", result: "Results" };

// ---- geography helpers (districts is a list: [] jurisdiction-wide · [slug…] specific ridings) ----
var MY_DISTRICTS = ["edmonton-strathcona"]; // the example signed-in resident's home riding(s)
function postDistricts(p) { return p.districts || []; }
function inMyDistricts(p) { return postDistricts(p).some(function (s) { return MY_DISTRICTS.indexOf(s) >= 0; }); }
function districtTag(p) {
  var ds = postDistricts(p);
  if (!ds.length) return "";
  return ds.length === 1 ? districtName(ds[0]) : (districtName(ds[0]) + " +" + (ds.length - 1));
}

// ---- count scaling: shown counts shrink as the Verified filter rises (fewer qualifying voices) ----
// social = comments + agree/disagree reactions (drop at every level).
// civic  = petition signatures + poll votes — only drop at Official, since Alberta participation
//          already requires residency verification (so ID/Residency filters don't thin them).
var SOCIAL_SCALE = [1, 0.62, 0.34, 0.08];
var CIVIC_SCALE  = [1, 1, 1, 0.12];
function scaleSocial(n) { return Math.max(0, Math.round(n * SOCIAL_SCALE[state.verified])); }
function scaleCivic(n)  { return Math.max(0, Math.round(n * CIVIC_SCALE[state.verified])); }

// the filter matrix: record types × subscribed jurisdictions × Refine (verified / my districts)
function feedMatches(p) {
  var rt = state.recordTypes.filter(function (r) { return r.name === FEED_TYPE_NAME[p.type]; })[0];
  if (!rt || !rt.included) return false;              // record-type include filter
  var sub = subByName(p.jur);
  if (!sub || !sub.included) return false;            // jurisdiction (unified-feed) filter
  if (p.tier < state.verified) return false;          // minimum author verification
  // My Districts: keep all Global posts, but limit jurisdiction content to your own ridings
  if (state.myDistricts && p.jur !== "Global" && !inMyDistricts(p)) return false;
  return true;
}

// build one card; returns a <g> with a ._h height property the caller stacks by.
// opts.hideJur / opts.hideDistrict drop the redundant tag parts the page already implies.
function buildCard(p, opts) {
  opts = opts || {};
  var W = 370, px = 16;
  var g = document.createElementNS(SVG_NS, "g");
  var kids = [], hits = [];
  function add(n) { kids.push(n); return n; }
  function hit(n) { hits.push(n); return n; }

  // author row
  var av = document.createElementNS(SVG_NS, "circle");
  av.setAttribute("cx", px + 14); av.setAttribute("cy", 26); av.setAttribute("r", 14);
  av.setAttribute("fill", "#e8e8e8"); av.setAttribute("stroke", "#ccc"); add(av);
  var ini = (p.author.split(" ").map(function (s) { return s[0]; }).join("")).slice(0, 2).toUpperCase();
  var it = txt(px + 14, 30, ini, 11, "#777"); it.setAttribute("text-anchor", "middle"); add(it);
  var nm = txt(px + 38, 22, p.author, 13.5, "#333"); nm.setAttribute("font-weight", "bold"); add(nm);
  add(txt(px + 38, 37, "@" + p.handle, 11.5, "#999"));
  // author tap → public profile (stub)
  var aHit = document.createElementNS(SVG_NS, "g"); clickRect(aHit, 0, 8, 190, 34, navStub("content-profile.svg")); hit(aHit);
  // right side: verification tier + jurisdiction/district tag
  if (p.tier > 0) {
    add(icon("#ic-shield", W - px - 88, 13, 14, "#666"));
    var tl = txt(W - px, 24, tierLabel(p.tier), 11.5, "#666"); tl.setAttribute("text-anchor", "end"); add(tl);
  }
  // jurisdiction/district tag — hidden parts are inferred from the page / selector context
  var parts = [];
  if (!opts.hideJur) parts.push(p.jur);
  if (!opts.hideDistrict) { var dt = districtTag(p); if (dt) parts.push(dt); }
  var tag = parts.join(" · ");
  if (tag) { var tg = txt(W - px, 38, tag, 11.5, "#999"); tg.setAttribute("text-anchor", "end"); add(tg); }

  // title (tap → post)
  var ti = txt(px, 66, p.title, 15, "#222"); ti.setAttribute("font-weight", "bold"); add(ti);

  // body (clamped to two lines) + …more (tap → post, same as title)
  add(txt(px, 90, p.body[0], 12.5, "#777"));
  add(txt(px, 108, p.body[1] || "", 12.5, "#777"));
  var more = txt(px, 130, "…more", 12.5, "#333"); more.setAttribute("font-weight", "bold"); add(more);
  var postHit = document.createElementNS(SVG_NS, "g");
  clickRect(postHit, px - 4, 54, W - 2 * px + 8, 22, navStub("content-post.svg")); // title row
  clickRect(postHit, px - 4, 120, 80, 18, navStub("content-post.svg"));            // …more
  hit(postHit);

  // type-specific section
  var y = 150;
  if (p.type === "petition") {
    var sig = scaleCivic(p.sig);
    var frac = clamp(sig / p.goal, 0, 1);
    add(rect(px, y + 2, W - 2 * px, 10, 5, "#f2f2f2", "#ccc"));
    add(rect(px, y + 2, Math.round((W - 2 * px) * frac), 10, 5, "#333"));
    add(txt(px, y + 32, fmt(sig) + " / " + fmt(p.goal) + " signatures", 12, "#555"));
    var cta = rect(px, y + 44, 150, 26, 13, "#ffffff", "#333"); add(cta);
    var ct = txt(px + 75, y + 61, "Sign the Petition", 12.5, "#333"); ct.setAttribute("text-anchor", "middle"); add(ct);
    y += 84;
  } else if (p.type === "poll") {
    var total = p.options.reduce(function (a, o) { return a + o.v; }, 0) || 1;
    p.options.forEach(function (o) {
      var ov = scaleCivic(o.v), bw = W - 2 * px;
      add(rect(px, y, bw, 18, 4, "#f4f4f4", "#e2e2e2"));
      add(rect(px, y, Math.round(bw * (o.v / total)), 18, 4, "#e3e3e3"));
      add(txt(px + 8, y + 13, o.label, 11.5, "#555"));
      var pv = txt(W - px - 6, y + 13, fmt(ov), 11.5, "#777"); pv.setAttribute("text-anchor", "end"); add(pv);
      y += 24;
    });
    y += 4;
  } else if (p.type === "result") {
    add(rect(px, y, W - 2 * px, 28, 6, "#f7f7f7", "#ddd"));
    add(icon("#ic-check-circle", px + 8, y + 6, 16, "#555"));
    add(txt(px + 32, y + 19, p.outcome, 12.5, "#444"));
    y += 38;
  }

  // footer: reactions (where applicable) + comments
  var fy = y + 14;
  if (hasReactions(p)) {
    add(txt(px, fy, "✓ " + fmt(scaleSocial(p.agree)), 13, "#555"));
    add(txt(px + 66, fy, "✗ " + fmt(scaleSocial(p.disagree)), 13, "#999"));
  } else if (p.type === "poll") {
    var tv = p.options.reduce(function (a, o) { return a + scaleCivic(o.v); }, 0);
    add(txt(px, fy, fmt(tv) + " votes", 13, "#555"));
  } else {
    add(txt(px, fy, fmt(scaleCivic(p.sig)) + " signatures", 13, "#555"));
  }
  add(icon("#ic-message", W - px - 64, fy - 13, 15, "#777"));
  var cc = txt(W - px, fy, fmt(scaleSocial(p.comments)), 13, "#777"); cc.setAttribute("text-anchor", "end"); add(cc);

  var cardH = fy + 16;
  // border behind content
  g.appendChild(rect(0, 0, W, cardH, 12, "#ffffff", "#ccc"));
  kids.forEach(function (n) { g.appendChild(n); });
  hits.forEach(function (n) { g.appendChild(n); }); // click targets on top
  g._h = cardH;
  return g;
}

var feedMax = 0;
function buildFeed() {
  var list = $("feedList");
  while (list.firstChild) list.removeChild(list.firstChild);
  var X = 30, y = 124, GAP = 14;
  // single jurisdiction selected ⇒ the selector already names it, so drop the jur tag on cards
  var single = state.subs.filter(function (s) { return s.included; }).length === 1;
  var shown = POSTS.filter(feedMatches);
  if (shown.length === 0) {
    var e1 = txt(215, 320, "No posts match the current filter.", 14, "#999");
    e1.setAttribute("text-anchor", "middle"); list.appendChild(e1);
    var e2 = txt(215, 344, "Adjust record types · jurisdictions · Refine (F).", 12, "#bbb");
    e2.setAttribute("text-anchor", "middle"); list.appendChild(e2);
  }
  shown.forEach(function (p) {
    var card = buildCard(p, { hideJur: single });
    card.setAttribute("transform", "translate(" + X + "," + y + ")");
    list.appendChild(card);
    y += card._h + GAP;
  });
  feedMax = Math.max(0, y - 885 + 8);
  state.feedScroll = clamp(state.feedScroll, 0, feedMax);
  $("feedScroll").setAttribute("transform", "translate(0," + (-state.feedScroll) + ")");
}

function render() {
  // My Districts requires a residency-verified account — never let it stick otherwise
  if (state.kyc < 2) state.myDistricts = false;
  buildFeed();

  // auth state + its callout
  show($("loginGlyph"), !state.loggedIn);
  show($("profileGlyph"), state.loggedIn);
  $("authCircle").setAttribute("fill", state.loggedIn ? "#333" : "#ffffff");
  $("annoLoginA").textContent = state.loggedIn ? "Signed in (avatar shown)" : "Logged out";
  $("annoLoginB").textContent = state.loggedIn ? "tap → profile (L to toggle)" : "tap → register / log in (L)";

  // selector label reflects the unified-feed filter
  $("curJur").textContent = pillLabel();

  // dropdown
  if (state.dropdownOpen) buildDropdown();
  show($("dropdown"), state.dropdownOpen);
  show($("modal"), state.modalOpen);

  // feed filter dropdown (left button)
  if (state.filterOpen) buildFilter();
  show($("filterDropdown"), state.filterOpen);

  // logged-out auth flow: chooser → register form → verify (OTP + passkey) · or → login
  var inAuth = !state.loggedIn;
  show($("authModal"),     inAuth && state.authView === "choose");
  show($("registerModal"), inAuth && state.authView === "register");
  show($("verifyModal"),   inAuth && state.authView === "verify");
  show($("loginModal"),    inAuth && state.authView === "login");
  if (inAuth && state.authView === "login") buildLoginInner();

  // spotlight result: if Alberta is already subscribed, offer Delete instead of Join
  var hasAlberta = state.subs.some(function (s) { return s.name === "Alberta"; });
  var act = $("albertaAction");
  act.textContent = hasAlberta ? "Delete ✕" : "Join ›";
  act.setAttribute("fill", hasAlberta ? "#c0392b" : "#999");

  // profile modal (only meaningful while logged in)
  show($("profileModal"), state.profileOpen && state.loggedIn);
  $("kycBadgeText").textContent = KYC_TIERS[state.kyc];
  $("kycBadge").querySelector("rect").setAttribute("fill", state.kyc === 0 ? "#f2f2f2" : "#333");
  $("kycBadgeText").setAttribute("fill", state.kyc === 0 ? "#555" : "#fff");
  $("kycShield").setAttribute("stroke", state.kyc === 0 ? "#666" : "#fff");
  $("deviceLabel").textContent = "Devices & passkeys (" + state.deviceCount + ")";
  var more = state.deviceCount - 2;
  var moreEl = $("deviceMore");
  moreEl.textContent = "+" + more + " more";
  show(moreEl, more > 0);

  // theme preference toggle (button only — no app-wide repaint)
  var dark = state.theme === "Dark";
  $("themeValue").textContent = state.theme;
  $("themeIcon").setAttribute("href", dark ? "#ic-moon" : "#ic-sun");
  $("themeIcon").setAttributeNS(XLINK, "href", dark ? "#ic-moon" : "#ic-sun");

  // compose flow: where → type → compose (logged-in only)
  show($("whereModal"),   state.loggedIn && state.composeStep === "where");
  show($("typeModal"),    state.loggedIn && state.composeStep === "type");
  show($("composeModal"), state.loggedIn && state.composeStep === "compose");
  if (state.composeStep === "where") buildWhere();
  if (state.composeStep === "type") buildType();
  if (state.composeStep === "compose") {
    var jn = state.composeJur || "Global", sub = subByName(jn), rm = rootMeta(state.composeType);
    $("composeJurName").textContent = jn;
    $("composeJurIcon").setAttribute("href", sub ? sub.icon : "#ic-globe");
    $("composeJurIcon").setAttributeNS(XLINK, "href", sub ? sub.icon : "#ic-globe");
    $("composeTypeLabel").textContent = rm.label;
    $("composeTypeIcon").setAttribute("href", rm.icon);
    $("composeTypeIcon").setAttributeNS(XLINK, "href", rm.icon);
    show($("composeChangeBtn"), rootsFor(jn).length > 1); // nothing to change if only one root
    buildComposeEditor();                                 // type-specific fields + Post
    if (state.composeJurOpen) buildComposeJurMenu();
    show($("composeJurMenu"), state.composeJurOpen);
  }

  // fab icon + callout depend on the current page
  show($("fabCompose"), state.page === "feed");
  show($("fabFeed"), state.page !== "feed");
  $("annoFabA").textContent = state.page === "feed" ? "On Feed" : "On another page";
  $("annoFabB").textContent = state.page === "feed" ? "tap → compose a post (quill)" : "tap → go to Feed (newspaper)";

  // labels: chrome shown unless the full-screen profile sheet covers it;
  // overlay callouts only while that overlay is open;
  // the include-filter callout only when checkboxes are actually shown
  show($("anno-chrome"), state.labelsOn && !state.profileOpen);
  show($("anno-dropdown"), state.labelsOn && state.dropdownOpen);
  show($("anno-dd-filter"), state.labelsOn && state.dropdownOpen && state.subs.length > 1);
  show($("anno-filter"), state.labelsOn && state.filterOpen);
  show($("anno-modal"), state.labelsOn && state.modalOpen);
  show($("anno-auth"), state.labelsOn && !!state.authView && !state.loggedIn);
  show($("anno-profile"), state.labelsOn && state.profileOpen && state.loggedIn);
}

// ---- wiring --------------------------------------------------------------
$("filterBtn").addEventListener("click", function () { state.filterOpen = !state.filterOpen; state.dropdownOpen = false; render(); });
$("selectorBtn").addEventListener("click", function () { state.dropdownOpen = !state.dropdownOpen; state.filterOpen = false; render(); });
// wheel over the content area scrolls the feed (no scroll while an overlay is open)
$("content").addEventListener("wheel", function (e) {
  if (state.filterOpen || state.dropdownOpen || state.modalOpen || state.composeStep || state.profileOpen) return;
  e.preventDefault();
  state.feedScroll = clamp(state.feedScroll + e.deltaY, 0, feedMax);
  $("feedScroll").setAttribute("transform", "translate(0," + (-state.feedScroll) + ")");
}, { passive: false });
$("authBtn").addEventListener("click", onAuthClick);
$("fab").addEventListener("click", onFabClick);
$("modalBackdrop").addEventListener("click", closeOverlays);
$("filterBackdrop").addEventListener("click", closeOverlays); // click outside → close
$("ddBackdrop").addEventListener("click", closeOverlays);     // click outside → close
$("modalCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });   // X button
$("profileCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); }); // X button
$("authCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });    // X button
$("resultAlberta").addEventListener("click", function () {
  var i = state.subs.findIndex(function (s) { return s.name === "Alberta"; });
  if (i === -1) {
    state.subs.push({ name: "Alberta", icon: "#ic-building", included: true });
  } else {
    state.subs.splice(i, 1); // already subscribed → Delete removes it
    // never leave the feed with nothing selected
    if (!state.subs.some(function (s) { return s.included; })) state.subs[0].included = true;
  }
  state.modalOpen = false;
  state.dropdownOpen = true; // reopen list so the change is visible
  render();
});

// chooser modal: pick register or login (logged-out only)
$("authBackdrop").addEventListener("click", closeOverlays);
$("registerBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "register"; render(); });
$("loginBtn").addEventListener("click", function (e) {
  e.stopPropagation();
  if (!state.otpAllowed) { signIn(); }                                       // O off → direct passkey login
  else { state.authView = "login"; state.loginVerified = false; render(); }   // O on → OTP/passkey modal
});
$("recoverBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "register"; render(); }); // reset reuses register flow

// register form: submit sends the registration OTP email, then opens the verify page
$("registerBackdrop").addEventListener("click", closeOverlays);
$("registerCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("regSubmitBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "verify"; render(); });

// verify page: enter OTP, tap Register Passkey → enrols this device's passkey and signs in
$("verifyBackdrop").addEventListener("click", closeOverlays);
$("verifyCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("regPasskeyBtn").addEventListener("click", function (e) { e.stopPropagation(); signIn(); });
$("verifyResendBtn").addEventListener("click", function (e) { e.stopPropagation(); /* resend OTP — deferred */ });

// login modal (returning user): body + handlers are built in buildLoginInner()
$("loginBackdrop").addEventListener("click", closeOverlays);
$("loginCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });

// compose flow: where → type → compose
$("whereBackdrop").addEventListener("click", closeOverlays);
$("whereCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("typeBackdrop").addEventListener("click", closeOverlays);
$("typeCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("composeBackdrop").addEventListener("click", closeOverlays);
$("composeCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("composeJurBtn").addEventListener("click", function (e) { e.stopPropagation(); state.composeJurOpen = !state.composeJurOpen; render(); });
$("composeChangeBtn").addEventListener("click", function (e) { e.stopPropagation(); state.composeStep = "type"; state.composeJurOpen = false; render(); });

// profile modal actions
$("profileBackdrop").addEventListener("click", closeOverlays);
$("logoutBtn").addEventListener("click", logout);
$("validateBtn").addEventListener("click", function (e) {
  e.stopPropagation();
  state.kyc = (state.kyc + 1) % KYC_TIERS.length; // demo: cycle the tier badge
  render();
});
$("addDeviceBtn").addEventListener("click", function (e) { e.stopPropagation(); state.deviceCount++; render(); });
$("addDeviceEmailBtn").addEventListener("click", function (e) { e.stopPropagation(); state.otpAllowed = true; render(); }); // open the OTP-login window for the new device

// direct account-settings items (each its own destination — deferred no-ops)
["editProfileBtn", "changeAddrBtn", "privacySettingsBtn", "jurisdictionsBtn", "termsBtn", "privacyBtn"].forEach(function (id) {
  $(id).addEventListener("click", function (e) { e.stopPropagation(); /* deferred */ });
});

// theme: live toggle (Light ↔ Dark) — preference only, no page flip
$("themeBtn").addEventListener("click", function (e) {
  e.stopPropagation();
  state.theme = (state.theme === "Light") ? "Dark" : "Light";
  render();
});

document.addEventListener("keydown", function (e) {
  switch (e.key) {
    case "l": case "L":
      // quick toggle: sign in / out (logging out also closes the profile)
      state.loggedIn = !state.loggedIn;
      if (!state.loggedIn) state.profileOpen = false;
      render();
      break;
    case "v": case "V": state.labelsOn = !state.labelsOn; render(); break;
    case "j": case "J": state.dropdownOpen = !state.dropdownOpen; state.filterOpen = false; render(); break;
    case "f": case "F": state.filterOpen = !state.filterOpen; state.dropdownOpen = false; render(); break;
    case "a": case "A": openModal(); break;
    case "o": case "O": state.otpAllowed = !state.otpAllowed; state.loginVerified = false; render(); break; // OTP-login window
    case "p": case "P": state.page = (state.page === "feed") ? "other" : "feed"; render(); break;
    case "Escape": closeOverlays(); break;
  }
});

render();
